import{_ as a,o as s,c as t,ag as i}from"./chunks/framework.BYYsWsaA.js";const u=JSON.parse('{"title":"Selfbots","description":"","frontmatter":{},"headers":[],"relativePath":"selfbots.md","filePath":"selfbots.md"}'),o={name:"selfbots.md"};function l(n,e,r,d,h,p){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="selfbots" tabindex="-1">Selfbots <a class="header-anchor" href="#selfbots" aria-label="Permalink to &quot;Selfbots&quot;">​</a></h1><p>A <strong>Selfbot</strong> (User API Key) lets you automate your own Parley account — the key authenticates as you directly.</p><div class="info custom-block"><p class="custom-block-title">Selfbots are allowed on Parley</p><p>Unlike Discord, Parley explicitly permits selfbots. Use them however you&#39;d like.</p></div><h2 id="creating-a-user-api-key" tabindex="-1">Creating a User API Key <a class="header-anchor" href="#creating-a-user-api-key" aria-label="Permalink to &quot;Creating a User API Key&quot;">​</a></h2><ol><li>Open <strong>User Settings → Developer</strong></li><li>Click <strong>+ Create Key</strong></li><li>Select <strong>User (Selfbot)</strong></li><li>Optionally give the key a name (e.g. &quot;Personal automation&quot;)</li><li>Copy the key — it is only shown once</li></ol><h2 id="how-selfbot-messages-appear-in-chat" tabindex="-1">How selfbot messages appear in chat <a class="header-anchor" href="#how-selfbot-messages-appear-in-chat" aria-label="Permalink to &quot;How selfbot messages appear in chat&quot;">​</a></h2><p>Messages sent via a User API Key show a 🤖 robot icon next to your username. Hovering over it shows <strong>&quot;Selfbot&quot;</strong>. Your username and avatar are used normally — it&#39;s clearly still you.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dylan 🤖  12:34 PM</span></span>
<span class="line"><span>  Automated reply</span></span></code></pre></div><p>The <code>via_api: true</code> field is set on every message sent through a User API Key.</p><h2 id="sending-a-message-as-yourself" tabindex="-1">Sending a message as yourself <a class="header-anchor" href="#sending-a-message-as-yourself" aria-label="Permalink to &quot;Sending a message as yourself&quot;">​</a></h2><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">POST</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /api/channels/{channelId}/messages</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Authorization</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Bearer plk_&lt;your-user-key&gt;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Content-Type</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> application/json</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;content&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;This is an automated message.&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The message is attributed to your account with <code>via_api: true</code>.</p><h2 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">​</a></h2><p>A User API Key has the same permissions as your account. You can:</p><ul><li>Read and send messages in any channel you&#39;re a member of</li><li>Edit and delete your own messages</li><li>Manage servers and channels you own/admin</li><li>Use DMs</li><li>Subscribe to the WebSocket for real-time events</li></ul><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><ul><li>User API Keys have full access to your account — treat them like passwords</li><li>You can revoke a key at any time from <strong>User Settings → Developer</strong></li><li>Multiple keys can be active at once</li><li>The raw key is never stored — only a SHA-256 hash</li></ul><h2 id="bot-vs-selfbot-at-a-glance" tabindex="-1">Bot vs. Selfbot at a glance <a class="header-anchor" href="#bot-vs-selfbot-at-a-glance" aria-label="Permalink to &quot;Bot vs. Selfbot at a glance&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Bot</th><th>Selfbot</th></tr></thead><tbody><tr><td>Separate account</td><td>✅ Yes</td><td>❌ No — authenticates as you</td></tr><tr><td>Badge in chat</td><td>Purple <strong>BOT</strong></td><td>🤖 Selfbot icon</td></tr><tr><td><code>author_is_bot</code></td><td><code>true</code></td><td><code>false</code></td></tr><tr><td><code>via_api</code></td><td><code>true</code></td><td><code>true</code></td></tr><tr><td>Needs server membership</td><td>Must be added</td><td>Already a member (it&#39;s you)</td></tr></tbody></table>`,19)])])}const g=a(o,[["render",l]]);export{u as __pageData,g as default};
